__global__ void layerforward_kernel(float *l1, float *l2, float **conn, int n1, int n2)
{
  int j = blockIdx.x * blockDim.x + threadIdx.x;
  if (j >= 1 && j <= n2) {
    float sum = 0.0;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k][j] * l1[k];
    }
    l2[j] = 1.0 / (1.0 + exp(-sum));
  }
}

void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  l1[0] = 1.0;

  float *dev_l1, *dev_l2;
  float **dev_conn;
  float *dev_conn_rows[n1 + 1];

  cudaMalloc(&dev_l1, (n1 + 1) * sizeof(float));
  cudaMalloc(&dev_l2, (n2 + 1) * sizeof(float));
  cudaMalloc(&dev_conn, (n1 + 1) * sizeof(float*));

  cudaMemcpy(dev_l1, l1, (n1 + 1) * sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(dev_l2, l2, (n2 + 1) * sizeof(float), cudaMemcpyHostToDevice);

  for (int i = 0; i <= n1; i++) {
    cudaMalloc(&dev_conn_rows[i], (n2 + 1) * sizeof(float));
    cudaMemcpy(dev_conn_rows[i], conn[i], (n2 + 1) * sizeof(float), cudaMemcpyHostToDevice);
  }
  cudaMemcpy(dev_conn, dev_conn_rows, (n1 + 1) * sizeof(float*), cudaMemcpyHostToDevice);

  int threads = 256;
  int blocks = (n2 + threads - 1) / threads;
  layerforward_kernel<<<blocks, threads>>>(dev_l1, dev_l2, dev_conn, n1, n2);
  cudaDeviceSynchronize();

  cudaMemcpy(l2, dev_l2, (n2 + 1) * sizeof(float), cudaMemcpyDeviceToHost);

  cudaFree(dev_l1);
  cudaFree(dev_l2);
  cudaFree(dev_conn);
  for (int i = 0; i <= n1; i++) {
    cudaFree(dev_conn_rows[i]);
  }
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err)
{
  int j;
  float o, t, errsum;
  errsum = 0.0;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0 - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err)
{
  int j, k;
  float h, sum, errsum;

  errsum = 0.0;
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0 - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

__global__ void adjust_weights_kernel(float *delta, float *ly, float **w, float **oldw, int ndelta, int nly)
{
  int j = blockIdx.x * blockDim.x + threadIdx.x;
  if (j >= 1 && j <= ndelta) {
    for (int k = 0; k <= nly; k++) {
      float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
  ly[0] = 1.0;

  float *dev_delta, *dev_ly;
  float **dev_w, **dev_oldw;
  float *dev_w_rows[nly + 1];
  float *dev_oldw_rows[nly + 1];

  cudaMalloc(&dev_delta, (ndelta + 1) * sizeof(float));
  cudaMalloc(&dev_ly, (nly + 1) * sizeof(float));
  cudaMalloc(&dev_w, (nly + 1) * sizeof(float*));
  cudaMalloc(&dev_oldw, (nly + 1) * sizeof(float*));

  cudaMemcpy(dev_delta, delta, (ndelta + 1) * sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(dev_ly, ly, (nly + 1) * sizeof(float), cudaMemcpyHostToDevice);

  for (int i = 0; i <= nly; i++) {
    cudaMalloc(&dev_w_rows[i], (ndelta + 1) * sizeof(float));
    cudaMalloc(&dev_oldw_rows[i], (ndelta + 1) * sizeof(float));
    cudaMemcpy(dev_w_rows[i], w[i], (ndelta + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(dev_oldw_rows[i], oldw[i], (ndelta + 1) * sizeof(float), cudaMemcpyHostToDevice);
  }
  cudaMemcpy(dev_w, dev_w_rows, (nly + 1) * sizeof(float*), cudaMemcpyHostToDevice);
  cudaMemcpy(dev_oldw, dev_oldw_rows, (nly + 1) * sizeof(float*), cudaMemcpyHostToDevice);

  int threads = 256;
  int blocks = (ndelta + threads - 1) / threads;
  adjust_weights_kernel<<<blocks, threads>>>(dev_delta, dev_ly, dev_w, dev_oldw, ndelta, nly);
  cudaDeviceSynchronize();

  for (int i = 0; i <= nly; i++) {
    cudaMemcpy(w[i], dev_w_rows[i], (ndelta + 1) * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(oldw[i], dev_oldw_rows[i], (ndelta + 1) * sizeof(float), cudaMemcpyDeviceToHost);
  }

  cudaFree(dev_delta);
  cudaFree(dev_ly);
  cudaFree(dev_w);
  cudaFree(dev_oldw);
  for (int i = 0; i <= nly; i++) {
    cudaFree(dev_w_rows[i]);
    cudaFree(dev_oldw_rows[i]);
  }
}

void bpnn_feedforward(BPNN *net)
{
  int in, hid, out;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units,
      net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units,
      net->hidden_weights, hid, out);
}

void bpnn_train(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units,
      net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units,
      net->hidden_weights, hid, out);

  bpnn_output_error(net->output_delta, net->target, net->output_units,
      out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out,
      net->hidden_weights, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;

  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid,
      net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in,
      net->input_weights, net->input_prev_weights);
}

